import{_ as t,o as e,c as n,a2 as i}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"X-Ray Offline System","text":"User Manual","actions":[{"theme":"brand","text":"Persyaratan & Instalasi","link":"/getting-started"},{"theme":"alt","text":"Panduan","link":"/guide/input-data"}]},"features":[{"icon":"📦","title":"Manajemen Manifest","details":"Kelola data manifest kargo melalui input manual atau import Excel. Hal ini bertujuan untuk memberikan kontrol kepada pengguna mana cargo yang telah complete scan, sebagian, atau belum sama sekali"},{"icon":"🎥","title":"Screening Real-time","details":"Mirroring screen Top View dan Side View dari sistem XRay."},{"icon":"🗄️","title":"Repository Lokal","details":"Seluruh data kargo, riwayat scan, dan gambar tersimpan di SQLite dan folder local workstation."},{"icon":"🤖","title":"Auto Crop & Manual Crop","details":"Pilihan penggunaan AI dalam Cropping area Cargo: OpenCV (server-side), MediaPipe (client-side), atau Manual cropping."},{"icon":"📊","title":"Customs Dashboard","details":"Monitoring real-time untuk petugas bea cukai dengan metrik dan panel detail"},{"icon":"🔄","title":"Konsolidasi Laporan","details":"Sinkronisasi data antar Workstation ke Central Hub, dan ke Cloud"}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),r={name:"index.md"};function s(o,a,d,l,u,g){return e(),n("div",null,[...a[0]||(a[0]=[i('<h2 id="fitur-utama" tabindex="-1">Fitur Utama <a class="header-anchor" href="#fitur-utama" aria-label="Permalink to &quot;Fitur Utama&quot;">​</a></h2><ul><li><strong>Manajemen Manifest:</strong> Pengelolaan data kargo melalui input manual atau impor massal via Excel.</li><li><strong>Screening Real-time:</strong> Pengambilan gambar otomatis dari kamera Top View dan Side View saat keputusan direkam.</li><li><strong>Penyimpanan Lokal (SQLite):</strong> Seluruh data kargo, riwayat scan, dan pengaturan tersimpan di database <code>xray.db</code>.</li><li><strong>Penyimpanan Gambar:</strong> Citra X-Ray disimpan sebagai file PNG lossless di folder <code>uploads/</code> pada server.</li><li><strong>Deteksi Koli Otomatis:</strong> Integrasi AI dengan OpenCV, MediaPipe, atau mode manual.</li><li><strong>Offline First:</strong> Seluruh operasional inti berjalan tanpa koneksi internet.</li><li><strong>Multi-Tingkat:</strong> Mendukung arsitektur Workstation, Hub, dan Cloud.</li></ul><h2 id="peran-aplikasi" tabindex="-1">Peran Aplikasi <a class="header-anchor" href="#peran-aplikasi" aria-label="Permalink to &quot;Peran Aplikasi&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Peran</th><th>Deskripsi</th></tr></thead><tbody><tr><td><strong>Workstation</strong></td><td>Input data screening dan scanning, melekat pada sistem XRay.</td></tr><tr><td><strong>Hub</strong></td><td>Server pusat yang mengkonsolidasi data dari beberapa Workstation.</td></tr><tr><td><strong>Cloud</strong></td><td>Server tingkat atas untuk agregasi data antar Hub dan pelaporan terpusat.</td></tr></tbody></table><h2 id="hak-akses" tabindex="-1">Hak Akses <a class="header-anchor" href="#hak-akses" aria-label="Permalink to &quot;Hak Akses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>Akses</th></tr></thead><tbody><tr><td><strong>USER</strong></td><td>Data Cargo, Screening, Scan History, Settings</td></tr><tr><td><strong>CUSTOMS</strong></td><td>Hanya Customs Dashboard</td></tr><tr><td><strong>Admin</strong></td><td>Semua fitur + Manajemen Pengguna</td></tr></tbody></table>',6)])])}const k=t(r,[["render",s]]);export{p as __pageData,k as default};
